# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
import pandas as pd
from collections import Counter

app = Flask(__name__)

# Store the labels in memory for simplicity. In real case scenario, you should use a database system to store them safely.
labels_db = {}  # key: image id, value: {annotator1: label1, annotator2: label2,...}

@app.route('/label', methods=['POST'])
def add_label():
    data = request.get_json()
    if 'image_id' not in data or 'username' not in data or 'label' not in data:
        return jsonify({"error": "missing fields (image_id, username, label) in the post data"}), 400
    
    image_id = data['image_id']
    if image_id not in labels_db:
        labels_db[image_id] = {}
        
    # aggregate new label for this user
    labels_db[image_id][data['username']] = data['label']
    
    return jsonify({"status": "successfully received the label"}), 201

@app.route('/vote', methods=['GET'])
def get_aggregated_labels():
    image_id = request.args.get('image_id')
    if not image_id or image_id not in labels_db:
        return jsonify({"error": "no such image_id in the system"}), 400
    
    # vote for each label using majority voting rule
    counter = Counter(labels_db[image_id].values())
    winner, _ = counter.most_common(1)[0]
  
    return jsonify({"label": winner})

if __name__ == "__main__":
    app.run(debug=True)  # run on local machine for testing